function updateOverview(){let e=document.getElementById("overviewCanvas");if(!e)return;document.getElementById("overviewBar");let t=e.offsetWidth,a=e.offsetHeight;if(0===t||0===a)return;e.width=t,e.height=a;let l=e.getContext("2d");l.clearRect(0,0,t,a);let n=state.pageCount,o=state.tracks,i=a/Math.max(o.length,1),g=t/n;for(let e=0;e<n;e++){let t=e*g;for(let a=0;a<o.length;a++){let n=o[a],r=a*i,s=getPageSteps(n,e),d=g/state.stepCount;for(let e=0;e<state.stepCount;e++){let a=s[e];if(a&&a.gate){let o=.55+.45*(a.velocity/127);l.fillStyle=n.color,l.globalAlpha=o,l.fillRect(t+e*d+.5,r+1,Math.max(d-1,1),i-2)}}}}l.globalAlpha=1,l.strokeStyle="rgba(255,255,255,0.07)",l.lineWidth=1;for(let e=1;e<n;e++){let t=Math.round(e*g);l.beginPath(),l.moveTo(t,0),l.lineTo(t,a),l.stroke()}let r=state.viewPage*g;if(l.strokeStyle="rgba(240,240,240,0.9)",l.lineWidth=2,l.strokeRect(r+1,1,g-2,a-2),state.playing&&state.currentPage!==state.viewPage){let e=state.currentPage*g;l.strokeStyle="rgba(255,56,100,0.7)",l.lineWidth=1.5,l.strokeRect(e+1.5,1.5,g-3,a-3)}document.getElementById("btnPagePrev").disabled=0===state.viewPage,document.getElementById("btnPageNext").disabled=state.viewPage>=state.pageCount-1&&state.pageCount>=MAX_PAGES}document.getElementById("overviewCanvas").addEventListener("click",e=>{let t=document.getElementById("overviewCanvas"),a=t.getBoundingClientRect(),l=Math.floor((e.clientX-a.left)/(t.offsetWidth/state.pageCount));l>=0&&l<state.pageCount&&navigateToPage(l)});